INSERT INTO email_templates (`key`, lang, subject, body_html) VALUES
('welcome','en','Welcome to Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">You&#039;re in!</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Ready to ask your crush out? Make your first invite — stay anonymous, keep it cute.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Open Crush</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Sent with care by Crush</div></div></div>'),
('magic','en','Your Crush sign-in link','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Tap to sign in</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Here is your magic link. It expires soon, so open it on this device.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Sign in</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Sent with care by Crush</div></div></div>'),
('invite','en','You have a crush invite','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/invite-envelope.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Someone has a crush on you</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;"><em style="color:#a06a8e;">&ldquo;{{message}}&rdquo;</em></p><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">A little date quest, just for you. Tap below to pick a day, a meal vibe, and where you would like to meet. No account needed.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Open my invite</a><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">Not interested? Block and report: {{unsubscribe}}</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Sent with care by Crush</div></div></div>'),
('result','en','{{crushName}} answered your invite','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">{{crushName}} said yes</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Here is what they picked. Your calendar invite is attached.</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">When</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Craving</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Pickup</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Map</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{mapHref}}</td></tr></table></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Sent with care by Crush</div></div></div>'),
('confirm','en','You are all set','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Your answer is on its way</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Nice! We sent your pick over. Here is what you chose:</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">When</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Craving</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Pickup</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">We will let you know when it is locked in.</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Sent with care by Crush</div></div></div>'),
('welcome','vi','Chào mừng đến với Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Bạn đã vào rồi!</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Sẵn sàng hỏi thả thính chưa? Tạo lời mời đầu tiên đi — giữ ẩn danh, thật dễ thương nha.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Mở Crush</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Gửi với tất cả tình yêu từ Crush</div></div></div>'),
('magic','vi','Link đăng nhập Crush của bạn','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Nhấn để đăng nhập</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Đây là magic link của bạn. Nó sẽ hết hạn sớm, nên mở ngay trên thiết bị này nhé.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Đăng nhập</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Gửi với tất cả tình yêu từ Crush</div></div></div>'),
('invite','vi','Bạn có một lời mời từ Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/invite-envelope.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Có người đang thích bạn đó</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;"><em style="color:#a06a8e;">&ldquo;{{message}}&rdquo;</em></p><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Một cuộc hẹn nhỏ xinh, dành riêng cho bạn. Nhấn bên dưới để chọn ngày, món ăn bạn thích, và nơi muốn gặp. Không cần tạo tài khoản đâu.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Mở lời mời của tôi</a><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">Không thích? Chặn và báo cáo: {{unsubscribe}}</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Gửi với tất cả tình yêu từ Crush</div></div></div>'),
('result','vi','{{crushName}} đã trả lời lời mời của bạn','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">{{crushName}} đồng ý rồi</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Đây là những gì họ đã chọn. Lịch hẹn đã được đính kèm nhé.</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Khi nào</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Thèm gì</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Điểm đón</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Bản đồ</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{mapHref}}</td></tr></table></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Gửi với tất cả tình yêu từ Crush</div></div></div>'),
('confirm','vi','Xong xuôi rồi nè','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Câu trả lời của bạn đang trên đường đến</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Tuyệt! Chúng mình đã gửi lựa chọn của bạn đi rồi. Đây là những gì bạn đã chọn:</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Khi nào</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Thèm gì</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Điểm đón</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">Chúng mình sẽ báo bạn khi mọi thứ được xác nhận.</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Gửi với tất cả tình yêu từ Crush</div></div></div>'),
('welcome','es','Bienvenido/a a Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">¡Ya estás dentro!</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">¿Listo/a para invitar a tu crush? Crea tu primera invitación — queda en anónimo, hazlo cute.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Abrir Crush</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Enviado con cariño por Crush</div></div></div>'),
('magic','es','Tu link de acceso a Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Toca para entrar</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Aquí está tu link mágico. Expira pronto, ábrelo desde este dispositivo.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Entrar</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Enviado con cariño por Crush</div></div></div>'),
('invite','es','Tienes una invitación en Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/invite-envelope.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Alguien tiene un crush en ti</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;"><em style="color:#a06a8e;">&ldquo;{{message}}&rdquo;</em></p><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Una citita especial, solo para ti. Toca abajo para elegir el día, qué te apetece comer y dónde quedar. Sin necesidad de cuenta.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Ver mi invitación</a><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">¿No te interesa? Bloquear y reportar: {{unsubscribe}}</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Enviado con cariño por Crush</div></div></div>'),
('result','es','{{crushName}} respondió tu invitación','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">{{crushName}} dijo que sí</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Esto es lo que eligió. Tu invitación de calendario ya está adjunta.</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Cuándo</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Antojo</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Punto de encuentro</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Mapa</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{mapHref}}</td></tr></table></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Enviado con cariño por Crush</div></div></div>'),
('confirm','es','Todo listo','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Tu respuesta ya va en camino</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">¡Genial! Enviamos tu elección. Esto es lo que escogiste:</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Cuándo</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Antojo</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Punto de encuentro</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">Te avisamos cuando todo esté confirmado.</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Enviado con cariño por Crush</div></div></div>'),
('welcome','zh','欢迎来到 Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">你进来啦！</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">准备好约你的心动对象了吗？发出第一个邀请吧 — 匿名发送，超可爱的。</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">打开 Crush</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush 用心送出</div></div></div>'),
('magic','zh','你的 Crush 登录链接','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">点击登录</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">这是你的魔法链接，马上就会过期，快在这台设备上打开哦。</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">登录</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush 用心送出</div></div></div>'),
('invite','zh','你收到了一个 Crush 邀请','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/invite-envelope.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">有人喜欢你</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;"><em style="color:#a06a8e;">&ldquo;{{message}}&rdquo;</em></p><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">一次小小的约会任务，专属于你。 点击下方选择日期、想吃什么，以及见面的地方。不需要注册账号。</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">查看我的邀请</a><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">不感兴趣？屏蔽并举报: {{unsubscribe}}</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush 用心送出</div></div></div>'),
