('confirm','zh','搞定啦','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">你的回复已经在路上了</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">耶！我们已经把你的选择发出去了。这是你选的内容：</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">时间</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">想吃什么</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">接送地点</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">确认好了我们会通知你的。</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush 用心送出</div></div></div>'),
('welcome','hi','Crush में आपका स्वागत है','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">आप आ गए!</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">अपने crush को date पर invite करने के लिए तैयार? पहला invite बनाएं — anonymous रहें, cute बने रहें।</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Crush खोलें</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush की तरफ से प्यार के साथ भेजा गया</div></div></div>'),
('magic','hi','आपका Crush sign-in link','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Sign in करने के लिए tap करें</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">ये रहा आपका magic link। ये जल्दी expire हो जाएगा, तो इसी device पर खोलें।</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Sign in करें</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush की तरफ से प्यार के साथ भेजा गया</div></div></div>'),
('invite','hi','आपके लिए एक crush invite आया है','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/invite-envelope.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">किसी को आप पर crush है</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;"><em style="color:#a06a8e;">&ldquo;{{message}}&rdquo;</em></p><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">आपके लिए एक छोटी सी date quest। नीचे tap करें और एक दिन, खाने का मूड, और मिलने की जगह चुनें। कोई account नहीं चाहिए।</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">मेरा invite खोलें</a><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">interest नहीं? Block और report करें: {{unsubscribe}}</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush की तरफ से प्यार के साथ भेजा गया</div></div></div>'),
('result','hi','{{crushName}} ने आपके invite का जवाब दिया','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">{{crushName}} ने हाँ कहा</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">उन्होंने जो चुना वो यहाँ है। आपका calendar invite attach है।</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">कब</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">क्या खाएं</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Pickup</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Map</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{mapHref}}</td></tr></table></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush की तरफ से प्यार के साथ भेजा गया</div></div></div>'),
