('confirm','pt','Tudo certo!','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Sua resposta tá a caminho</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Arrasou! A gente enviou sua escolha. Veja o que você selecionou:</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Quando</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Vontade de comer</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Ponto de encontro</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">A gente te avisa quando estiver confirmado.</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Enviado com carinho pelo Crush</div></div></div>'),
('welcome','fr','Bienvenue sur Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">T&#039;es dans la place !</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Prêt·e à inviter ton crush ? Fais ton premier invite — reste anonyme, reste cute.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Ouvrir Crush</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Envoyé avec soin par Crush</div></div></div>'),
