('result','fr','{{crushName}} a répondu à ton invite','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">{{crushName}} a dit oui</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Voilà ce qu&#039;il·elle a choisi. Ton invite de calendrier est en pièce jointe.</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Quand</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Envie de</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Point de rendez-vous</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Carte</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{mapHref}}</td></tr></table></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Envoyé avec soin par Crush</div></div></div>'),
('confirm','fr','C''est dans la boîte','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">Ta réponse est en route</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">Trop bien ! On a envoyé ton choix. Voilà ce que t&#039;as sélectionné :</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Quand</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Envie de</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">Point de rendez-vous</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">On te prévient quand c&#039;est confirmé.</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Envoyé avec soin par Crush</div></div></div>'),
('welcome','ko','Crush에 오신 걸 환영해요','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">가입 완료!</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">좋아하는 사람에게 데이트 신청할 준비됐나요? 첫 번째 초대장을 보내 보세요 — 익명으로, 귀엽게.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Crush 열기</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush가 마음을 담아 보냈어요</div></div></div>'),
('magic','ko','Crush 로그인 링크가 왔어요','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">탭해서 로그인하기</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">매직 링크가 왔어요. 곧 만료되니까 이 기기에서 바로 열어 주세요.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">로그인</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush가 마음을 담아 보냈어요</div></div></div>'),
('invite','ko','누군가가 초대장을 보냈어요','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/invite-envelope.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">누군가 당신을 좋아해요</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;"><em style="color:#a06a8e;">&ldquo;{{message}}&rdquo;</em></p><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">당신만을 위한 작은 데이트 퀘스트예요. 아래를 탭해서 날짜, 밥 분위기, 만날 장소를 골라 보세요. 계정 없이도 돼요.</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">초대장 열기</a><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">관심 없어요? 차단 및 신고: {{unsubscribe}}</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush가 마음을 담아 보냈어요</div></div></div>'),
('result','ko','{{crushName}}이(가) 초대에 답했어요','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">{{crushName}}이(가) 수락했어요</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">상대방이 고른 내용이에요. 캘린더 초대장도 첨부되어 있어요.</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">날짜</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">먹고 싶은 것</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">픽업</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">지도</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{mapHref}}</td></tr></table></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush가 마음을 담아 보냈어요</div></div></div>'),
('confirm','ko','완료됐어요','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">답변이 전달되고 있어요</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">좋아요! 선택한 내용을 전달했어요. 고르신 내용이에요:</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">날짜</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">먹고 싶은 것</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">픽업</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">확정되면 알려드릴게요.</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crush가 마음을 담아 보냈어요</div></div></div>'),
('welcome','ja','Crushへようこそ','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">登録完了！</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">好きな人をデートに誘う準備はできた？最初の招待状を送ってみよう — 匿名で、かわいく。</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">Crushを開く</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crushより、心を込めてお届けしました</div></div></div>'),
('magic','ja','Crushのサインインリンクが届いたよ','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">タップしてサインイン</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">マジックリンクが届いたよ。すぐ期限切れになるから、このデバイスで今すぐ開いてね。</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">サインイン</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crushより、心を込めてお届けしました</div></div></div>'),
('invite','ja','招待状が届いてるよ','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/invite-envelope.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">誰かがあなたを気になってる</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;"><em style="color:#a06a8e;">&ldquo;{{message}}&rdquo;</em></p><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">あなただけへの、ちいさなデートクエスト。 下をタップして、日にち・食事のムード・会う場所を選んでね。アカウントなしでOK。</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">招待状を開く</a><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">興味ない？ブロック＆報告: {{unsubscribe}}</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crushより、心を込めてお届けしました</div></div></div>'),
('result','ja','{{crushName}}が招待に返事をしたよ','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">{{crushName}}がOKしてくれた</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">相手が選んだ内容はこれ。カレンダーの招待状も添付してあるよ。</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">日時</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">食べたいもの</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">ピックアップ</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">マップ</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{mapHref}}</td></tr></table></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crushより、心を込めてお届けしました</div></div></div>'),
('confirm','ja','準備完了だよ','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">あなたの返事を送ったよ</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">やった！選んだ内容を送ったよ。こんな感じで選んだね：</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">日時</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">食べたいもの</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">ピックアップ</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">確定したらまた連絡するね。</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">Crushより、心を込めてお届けしました</div></div></div>'),
('welcome','th','ยินดีต้อนรับสู่ Crush','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">เข้าร่วมแล้ว!</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">พร้อมชวนคนที่แอบชอบออกเดทแล้วหรือยัง? ส่งคำเชิญแรกเลย — ไม่ระบุชื่อ น่ารักมาก</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">เปิด Crush</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">ส่งด้วยความห่วงใยจาก Crush</div></div></div>'),
('magic','th','ลิงก์เข้าสู่ระบบ Crush ของคุณ','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/crush-mascot.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">แตะเพื่อเข้าสู่ระบบ</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">นี่คือ magic link ของคุณ หมดอายุเร็วนะ เปิดบนอุปกรณ์นี้เลย</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">เข้าสู่ระบบ</a></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">ส่งด้วยความห่วงใยจาก Crush</div></div></div>'),
('invite','th','มีคนส่งคำเชิญมาให้คุณ','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/invite-envelope.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">มีคนแอบปิ๊งคุณอยู่</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;"><em style="color:#a06a8e;">&ldquo;{{message}}&rdquo;</em></p><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">เควสต์เดทเล็กๆ ที่ทำมาเพื่อคุณโดยเฉพาะ แตะด้านล่างเพื่อเลือกวัน บรรยากาศมื้ออาหาร และสถานที่นัดพบ ไม่ต้องมีแอคเคาท์ก็ได้</p><a href="{{link}}" style="display:block;text-align:center;padding:14px 20px;background:#ff3d8b;color:#ffffff;border-radius:14px;text-decoration:none;font-weight:700;font-size:15px;">เปิดคำเชิญของฉัน</a><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">ไม่สนใจ? บล็อกและรายงาน: {{unsubscribe}}</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">ส่งด้วยความห่วงใยจาก Crush</div></div></div>'),
('result','th','{{crushName}} ตอบรับคำเชิญของคุณแล้ว','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">{{crushName}} ตอบว่าใช่</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">นี่คือสิ่งที่เขา/เธอเลือก คำเชิญ calendar แนบมาด้วยแล้ว</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">เมื่อไหร่</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">อยากกินอะไร</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">จุดรับ</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">แผนที่</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{mapHref}}</td></tr></table></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">ส่งด้วยความห่วงใยจาก Crush</div></div></div>'),
('confirm','th','เรียบร้อยแล้ว','<div style="background:#f4ecff;padding:24px 12px;font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif;"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:18px;overflow:hidden;"><div style="background:#ff3d8b;padding:26px 24px;text-align:center;"><img src="https://crush.didudi.com/assets/generated/sent-heart.png" width="76" height="76" alt="" style="display:inline-block;border:0;outline:none;"><div style="color:#ffe3f1;font-size:12px;letter-spacing:2px;text-transform:uppercase;margin-top:8px;">Crush</div></div><div style="padding:26px 26px 22px;"><h1 style="margin:0 0 14px;font-size:21px;line-height:1.3;color:#5a2a52;font-weight:700;">คำตอบของคุณอยู่ระหว่างทาง</h1><p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#5f5e5a;">เยี่ยม! ส่งสิ่งที่คุณเลือกไปแล้ว นี่คือที่คุณเลือก:</p><table role="presentation" width="100%" style="border-collapse:collapse;margin:0 0 18px;background:#fbeaf0;border-radius:14px;"><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">เมื่อไหร่</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{when}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">อยากกินอะไร</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{meal}}</td></tr><tr><td style="padding:9px 16px;font-size:13px;color:#993556;font-weight:700;width:34%;">จุดรับ</td><td style="padding:9px 16px;font-size:13px;color:#72243e;">{{place}}</td></tr></table><p style="margin:18px 0 0;font-size:11px;line-height:1.5;color:#c3a7b8;text-align:center;">เราจะแจ้งให้รู้เมื่อทุกอย่างยืนยันแล้ว</p></div><div style="padding:14px 24px 20px;text-align:center;font-size:11px;color:#c3a7b8;">ส่งด้วยความห่วงใยจาก Crush</div></div></div>')
